import React from 'react';

export default function SSLBadge({ url }) {
  const isHttps = url?.startsWith('https');
  return (
    <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold whitespace-nowrap ${
      isHttps
        ? 'bg-green-100 text-green-700 dark:bg-transparent dark:text-gh-green-em dark:border dark:border-gh-green-em/30'
        : 'bg-yellow-100 text-yellow-700 dark:bg-transparent dark:text-yellow-400 dark:border dark:border-yellow-400/30'
    }`}>
      {isHttps ? '🔒' : '⚠️'} {isHttps ? 'HTTPS' : 'HTTP'}
    </span>
  );
}
